function petBurnEstimate(rarity, totalStars) {
  const starScores = {
    1: 7e3,
    2: 1e4,
    3: 19e3,
    4: 28e3,
    5: 4e4,
    6: 75e3,
    7: 225e3,
    8: 45e4,
    9: 1e6
  };
  const rarityScores = {
    0: 2e3,
    1: 25e3,
    2: 175e3,
    3: 37e4,
    4: 78e4
  };
  const starScore = starScores[totalStars] || 0;
  const rarityScore = rarityScores[rarity] || 0;
  const scoreNumerator = starScore + rarityScore;
  return {
    de: scoreNumerator / 15,
    gde: scoreNumerator / 240
  };
}
function getTopRollColor(pct) {
  if (pct === null) return "text-muted-foreground";
  if (pct >= 90) return "text-yellow-500";
  if (pct >= 75) return "text-purple-500";
  if (pct >= 50) return "text-blue-500";
  if (pct >= 25) return "text-green-500";
  return "text-muted-foreground";
}
function getTopRollBadgeVariant(pct) {
  if (pct === null) return "outline";
  if (pct >= 90) return "default";
  if (pct >= 75) return "default";
  return "secondary";
}
function getTopRollLabel(pct) {
  if (pct === null) return "N/A";
  if (pct >= 95) return "Perfect";
  if (pct >= 85) return "Excellent";
  if (pct >= 70) return "Great";
  if (pct >= 50) return "Good";
  if (pct >= 25) return "Fair";
  return "Low";
}
